import React, { useCallback, useMemo, useState } from 'react';
import { LinErpListFilterBar, Select, dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatNumber, formatVnd } from '../../../utils/formatters';
import { monthStartEnd, yearStartEnd } from '../../../utils/exportExcel';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import reportStyles from '../../../styles/erpReportPage.module.css';
import type { RevenueSummaryRow } from '../../../services/analytics/models';
import { AnalyticsReportShell, ReportTabBar, ReportTableWrap } from '../../../components/report';

const TEST_ID = 'erp-bao-cao-doanh-thu';
const PAGE_ID = 'baocao-doanh-thu';
const TABS = [
  { id: 'day', label: 'Ngày' },
  { id: 'month', label: 'Tháng' },
  { id: 'quarter', label: 'Quý' },
  { id: 'year', label: 'Năm' },
];

function defaultRange(tab: string) {
  if (tab === 'year') return yearStartEnd();
  return monthStartEnd();
}

const BaoCaoDoanhThuPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const [tab, setTab] = useState('month');
  const initial = defaultRange('month');
  const [fromDate, setFromDate] = useState(initial.fromDate);
  const [toDate, setToDate] = useState(initial.toDate);
  const [rows, setRows] = useState<RevenueSummaryRow[]>([]);
  const [loading, setLoading] = useState(false);

  const handleTabChange = useCallback((next: string) => {
    setTab(next);
    const r = defaultRange(next);
    setFromDate(r.fromDate);
    setToDate(r.toDate);
  }, []);

  const handleLoad = useCallback(() => {
    setLoading(true);
    analyticsService
      .getRevenueSummary({ fromDate, toDate, granularity: tab })
      .then(setRows)
      .catch(err =>
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, 'Lỗi tải báo cáo doanh thu'),
          type: 'error',
        }),
      )
      .finally(() => setLoading(false));
  }, [fromDate, toDate, tab, dispatch]);

  const totals = useMemo(
    () =>
      rows.reduce(
        (acc, r) => ({
          revenue: acc.revenue + r.revenue,
          cogs: acc.cogs + r.cogs,
          grossProfit: acc.grossProfit + r.grossProfit,
        }),
        { revenue: 0, cogs: 0, grossProfit: 0 },
      ),
    [rows],
  );
  const avgMargin = totals.revenue > 0 ? (totals.grossProfit / totals.revenue) * 100 : 0;

  const listFilters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={TEST_ID}
        fromDate={fromDate}
        toDate={toDate}
        onDateChange={(from, to) => {
          setFromDate(from ?? '');
          setToDate(to ?? '');
        }}
        dateLabel="Thời gian"
        expandDateRangeAriaLabel="Thêm ngày kết thúc"
        onSearch={handleLoad}
        searchAriaLabel="Xem"
        loading={loading}
        leading={(
          <div data-testid={`${TEST_ID}-field-granularity`}>
            <Select
              label="Kỳ"
              value={tab}
              onChange={e => handleTabChange(e.target.value)}
              options={TABS.map(t => ({ value: t.id, label: t.label }))}
              size="small"
            />
          </div>
        )}
      />
    ),
    [fromDate, toDate, tab, handleLoad, loading, handleTabChange],
  );

  return (
    <AnalyticsReportShell
      testId={TEST_ID}
      pageId={PAGE_ID}
      title="Báo cáo doanh thu"
      titleIconClass="fas fa-coins"
      loading={loading}
      hasData={rows.length > 0}
      filters={listFilters}
      onLoad={handleLoad}
      exportPath="/accounting/reports/revenue-summary/export-excel"
      exportParams={{ fromDate, toDate, granularity: tab }}
      exportFilename={`DoanhThu-${tab}.xlsx`}
      tabBar={<ReportTabBar testId={TEST_ID} tabs={TABS} activeId={tab} onChange={handleTabChange} />}
    >
      <ReportTableWrap testId={`${TEST_ID}-grid`}>
        <thead>
          <tr>
            <th className={reportStyles.colStt}>STT</th>
            <th>Kỳ</th>
            <th className={reportStyles.colRight}>Doanh thu</th>
            <th className={reportStyles.colRight}>Giá vốn</th>
            <th className={reportStyles.colRight}>LN gộp</th>
            <th className={reportStyles.colRight}>%</th>
          </tr>
        </thead>
        <tbody>
          {rows.map((r, i) => (
            <tr key={`${r.period}-${i}`}>
              <td className={reportStyles.colStt}>{i + 1}</td>
              <td>{r.period}</td>
              <td className={reportStyles.colRight}>{formatVnd(r.revenue)}</td>
              <td className={reportStyles.colRight}>{formatVnd(r.cogs)}</td>
              <td className={reportStyles.colRight}>{formatVnd(r.grossProfit)}</td>
              <td className={reportStyles.colRight}>{formatNumber(r.grossMargin)}%</td>
            </tr>
          ))}
          {rows.length > 0 && (
            <tr className={reportStyles.rowTotal}>
              <td className={reportStyles.colStt} />
              <td>Tổng cộng</td>
              <td className={reportStyles.colRight}>{formatVnd(totals.revenue)}</td>
              <td className={reportStyles.colRight}>{formatVnd(totals.cogs)}</td>
              <td className={reportStyles.colRight}>{formatVnd(totals.grossProfit)}</td>
              <td className={reportStyles.colRight}>{formatNumber(avgMargin)}%</td>
            </tr>
          )}
        </tbody>
      </ReportTableWrap>
    </AnalyticsReportShell>
  );
};

export default BaoCaoDoanhThuPage;
